import{c as a,a7 as r,y as t,B as l}from"./chunks/framework.BYQtDGaq.js";const d=JSON.parse('{"title":"常用强化学习环境汇总","description":"汇总常用的强化学习训练与测试环境资源","frontmatter":{"title":"常用强化学习环境汇总","description":"汇总常用的强化学习训练与测试环境资源"},"headers":[],"relativePath":"rl/environments/awesome-envs.md","filePath":"rl/environments/awesome-envs.md","lastUpdated":1782704182000}'),i={name:"rl/environments/awesome-envs.md"};function o(n,e,h,p,s,m){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="常用强化学习环境汇总" tabindex="-1">常用强化学习环境汇总 <a class="header-anchor" href="#常用强化学习环境汇总" aria-label="Permalink to “常用强化学习环境汇总”">​</a></h1><h2 id="gymnasium" tabindex="-1">Gymnasium <a class="header-anchor" href="#gymnasium" aria-label="Permalink to “Gymnasium”">​</a></h2><p><em>Gym</em>除了是最广为人知的基准测试之外，还是一个用于开发和比较强化学习算法的工具包。它支持教学智能体的所有内容，从行走模拟人形机器人（需要 MuJoCo，请参阅<a href="https://github.com/benelot/pybullet-gym" target="_blank" rel="noreferrer">PyBullet Gymperium</a>了解免费替代方案）到玩 Pong 或 Pinball 等 Atari 游戏。</p><p>Gymnium 是 OpenAI Gym 库的一个分支,（几年前 OpenAI 将维护工作交给了一个外部团队），现在 Openai 不在对 Gym 进行维护，现在主要由 Gymnium 进行维护。</p><ul><li><p>Github: <a href="https://gymnasium.farama.org/" target="_blank" rel="noreferrer">https://gymnasium.farama.org/</a></p></li><li><p>文档： <a href="https://github.com/Farama-Foundation/Gymnasium" target="_blank" rel="noreferrer">https://github.com/Farama-Foundation/Gymnasium</a></p></li></ul><h2 id="vizdoom" tabindex="-1">ViZDoom <a class="header-anchor" href="#vizdoom" aria-label="Permalink to “ViZDoom”">​</a></h2><p>ViZDoom 允许开发仅使用视觉信息（屏幕缓冲区）<strong>玩 Doom 的</strong>AI 机器人。它主要用于机器视觉学习，特别是深度强化学习的研究。</p><p>ViZDoom 基于<a href="https://zdoom.org/" target="_blank" rel="noreferrer">ZDoom</a>引擎提供游戏机制。</p><ul><li>项目地址： <a href="https://github.com/Farama-Foundation/ViZDoom" target="_blank" rel="noreferrer">https://github.com/Farama-Foundation/ViZDoom</a></li><li>在线文档： <a href="https://vizdoom.farama.org/" target="_blank" rel="noreferrer">https://vizdoom.farama.org/</a></li></ul><h2 id="pettingzoo" tabindex="-1">PettingZoo <a class="header-anchor" href="#pettingzoo" aria-label="Permalink to “PettingZoo”">​</a></h2><p>PettingZoo 用于进行多智能体强化学习研究环境，类似于 Gym 的多智能体版本。</p><ul><li><a href="https://pettingzoo.farama.org/" target="_blank" rel="noreferrer">https://pettingzoo.farama.org/</a></li><li><a href="https://github.com/Farama-Foundation/PettingZoo" target="_blank" rel="noreferrer">https://github.com/Farama-Foundation/PettingZoo</a></li></ul><h2 id="neural-mmo" tabindex="-1">Neural MMO <a class="header-anchor" href="#neural-mmo" aria-label="Permalink to “Neural MMO”">​</a></h2><p><a href="https://github.com/NeuralMMO/environment" target="_blank" rel="noreferrer">Neural MMO</a> 最初由 OpenAI 发布，作为测试多智能体强化学习方法的环境。 MMO 代表大型多人在线游戏，因为该项目的灵感来自于 MMORPG。该环境提供了优化的实现，您只需使用一个 CPU 即可运行数百个智能体。</p><ul><li><p>Github： <a href="https://github.com/NeuralMMO/environment" target="_blank" rel="noreferrer">https://github.com/NeuralMMO/environment</a></p></li><li><p>Pages: <a href="https://neuralmmo.github.io/_build/html/rst/landing.html" target="_blank" rel="noreferrer">https://neuralmmo.github.io/_build/html/rst/landing.html</a></p></li></ul><h2 id="android-env" tabindex="-1">Android Env <a class="header-anchor" href="#android-env" aria-label="Permalink to “Android Env”">​</a></h2><p><a href="https://github.com/deepmind/android_env" target="_blank" rel="noreferrer">Android Env</a>由 DeepMind 发布。它是一个为构建与 Android 操作系统交互的智能体提供平台的环境。Android Env 库将根据定义的任务返回像素观察结果和奖励。</p><p>使用此环境，可以训练智能体使用 RL 与 Android Env 交互并完成任务。</p><ul><li>Github： <a href="https://github.com/google-deepmind/android_env" target="_blank" rel="noreferrer">https://github.com/google-deepmind/android_env</a></li></ul><h2 id="deepmind-lab" tabindex="-1">DeepMind Lab <a class="header-anchor" href="#deepmind-lab" aria-label="Permalink to “DeepMind Lab”">​</a></h2><p><em>DeepMind Lab</em>是一个通过 ioquake3 和其他开源软件基于 Quake III Arena 的 3D 学习环境。 DeepMind Lab 为学习智能体提供了一套具有挑战性的 3D 导航和解谜任务。其主要目的是充当人工智能研究的测试平台，智能体必须根据视觉观察采取行动。</p><p>Github: <a href="https://github.com/google-deepmind/lab" target="_blank" rel="noreferrer">https://github.com/google-deepmind/lab</a></p><h2 id="dm-control" tabindex="-1">Dm_Control <a class="header-anchor" href="#dm-control" aria-label="Permalink to “Dm_Control”">​</a></h2><p><em>dm_control</em>软件包是<strong>Python 库和任务套件</strong>的集合，用于关节体模拟中的强化学习智能体。 MuJoCo 包装器提供了与函数和数据结构的便捷绑定，以创建您自己的任务。</p><p>此外，控制套件是一组具有标准化结构的固定任务，旨在作为性能基准。它包括 HalfCheetah、Humanoid、Hopper、Walker、Graber 等经典任务（见图）。 Locomotion 框架提供了足球等运动任务的高级抽象和示例。还包括一组带有机器人手臂和拼装积木的可配置操作任务。</p><ul><li>Github: <a href="https://github.com/google-deepmind/dm_control" target="_blank" rel="noreferrer">https://github.com/google-deepmind/dm_control</a></li></ul><h2 id="mujoco" tabindex="-1">MuJoCo <a class="header-anchor" href="#mujoco" aria-label="Permalink to “MuJoCo”">​</a></h2><p><a href="https://github.com/deepmind/mujoco" target="_blank" rel="noreferrer">MuJoCo</a>代表接触式多关节动力学。它由 DeepMind 发布。它是通用物理引擎，旨在促进机器人、生物力学、图形和动画、机器学习以及其他需要快速准确地模拟铰接结构与其环境相互作用的领域的研究和开发。</p><p>设计人体人工智能控制器以完成多样化的运动任务。该库由斯坦福大学实施，每年都会举办比赛，强化学习从业者可以在比赛中相互测试自己的技能。目前实施了三种环境：简化的手臂运动、学习跑步和腿部假肢。</p><ul><li><p>Github： <a href="https://github.com/google-deepmind/mujoco" target="_blank" rel="noreferrer">https://github.com/google-deepmind/mujoco</a></p></li><li><p>Pages: <a href="https://mujoco.org/" target="_blank" rel="noreferrer">https://mujoco.org/</a></p></li></ul><h2 id="opensim-rl" tabindex="-1">OpenSim-RL <a class="header-anchor" href="#opensim-rl" aria-label="Permalink to “OpenSim-RL”">​</a></h2><p>设计人体人工智能控制器以完成多样化的运动任务。该库由斯坦福大学实施，每年都会举办比赛，强化学习从业者可以在比赛中相互测试自己的技能。目前实施了三种环境：简化的手臂运动、学习跑步和腿部假肢。</p><ul><li><p>Github: <a href="https://github.com/stanfordnmbl/osim-rl" target="_blank" rel="noreferrer">https://github.com/stanfordnmbl/osim-rl</a></p></li><li><p>在线文档： <a href="http://osim-rl.stanford.edu/" target="_blank" rel="noreferrer">http://osim-rl.stanford.edu/</a></p></li></ul><h2 id="realworldrl-suite" tabindex="-1">Realworldrl_Suite <a class="header-anchor" href="#realworldrl-suite" aria-label="Permalink to “Realworldrl_Suite”">​</a></h2><p>《<a href="https://arxiv.org/abs/1904.12901" target="_blank" rel="noreferrer">现实世界 RL 的挑战》</a>论文识别并描述了目前阻碍强化学习 (RL) 智能体在现实世界应用程序和产品中使用的九个挑战。它还描述了一个评估框架和一组环境，可以评估 RL 算法对现实世界系统的潜在适用性。此后又发表了《对<a href="https://arxiv.org/pdf/2003.11881.pdf" target="_blank" rel="noreferrer">现实世界强化学习挑战的实证研究》论文</a>，该论文实现了所描述的九个挑战中的八个，并分析了它们对各种最先进的强化学习算法的影响。 这是用于执行此分析的代码库，也旨在作为一个通用平台，用于围绕这些挑战轻松重现实验。它被称为<em>realworldrl-suite</em>（真实世界强化学习（RWRL）套件）。</p><p>Github: <a href="https://github.com/google-research/realworldrl_suite" target="_blank" rel="noreferrer">https://github.com/google-research/realworldrl_suite</a></p><h2 id="pybullet-gym" tabindex="-1">PyBullet Gym <a class="header-anchor" href="#pybullet-gym" aria-label="Permalink to “PyBullet Gym”">​</a></h2><p><em>PyBullet Gymperium 是 OpenAI Gym MuJoCo 环境的开源实现，这些都是具有挑战性的连续控制环境，例如训练人形机器人行走。可与 OpenAI Gym 强化学习研究平台一起使用，以支持开放研究。</em></p><ul><li>Github： <a href="https://github.com/benelot/pybullet-gym" target="_blank" rel="noreferrer">https://github.com/benelot/pybullet-gym</a></li></ul><h2 id="finrl" tabindex="-1">FinRL <a class="header-anchor" href="#finrl" aria-label="Permalink to “FinRL”">​</a></h2><p><a href="https://github.com/AI4Finance-Foundation/FinRL" target="_blank" rel="noreferrer">FinRL</a>是最早的金融开源 RL 环境之一。它可以集成到各种数据源中，无论是数据源还是用户导入的数据集，甚至是模拟数据。</p><ul><li>Github: <a href="https://github.com/AI4Finance-Foundation/FinRL" target="_blank" rel="noreferrer">https://github.com/AI4Finance-Foundation/FinRL</a></li></ul><h2 id="recsim" tabindex="-1">RecSim <a class="header-anchor" href="#recsim" aria-label="Permalink to “RecSim”">​</a></h2><p><a href="https://github.com/google-research/recsim" target="_blank" rel="noreferrer">RecSim</a>是一个可配置的系统，用于将强化学习应用于推荐系统。 RecSim 模拟推荐智能体与由用户模型、文档模型和用户 选择 模型组成的环境的交互。</p><ul><li>Github: <a href="https://github.com/google-research/recsim" target="_blank" rel="noreferrer">https://github.com/google-research/recsim</a></li></ul><h2 id="rlcard" tabindex="-1">RLCard <a class="header-anchor" href="#rlcard" aria-label="Permalink to “RLCard”">​</a></h2><p><em>RLCard</em>是纸牌游戏中强化学习 (RL) 的工具包。它支持多种卡环境并具有易于使用的界面。游戏包括二十一点、UNO、限注德州扑克、斗地主等等！它还允许您创建自己的环境。 RLCard 的目标是架起强化学习和不完美信息博弈的桥梁。</p><p><a href="https://github.com/datamllab/rlcard" target="_blank" rel="noreferrer">RLCard</a>是支持各种纸牌游戏的 RL 环境。它由莱斯大学和德克萨斯农工大学的<a href="http://faculty.cs.tamu.edu/xiahu/" target="_blank" rel="noreferrer">DATA 实验室</a>以及社区贡献者开发。它支持多种游戏和算法，如下所示：</p><p>Some of the games supported :</p><ul><li>BlackJack</li><li>NoLimit Texas Hold ’em</li><li>Gin Rummy</li><li>Bridge</li><li>Dou Dizhu</li><li>Uno</li></ul><p>Some of Algorithms implemented are</p><ul><li>Counterfactual Regret minimization</li><li>Neural Fictitious Self-Play</li><li>Deep Q-Learning</li><li>Deep Monte-Carlo</li></ul><p>GIthub： <a href="https://github.com/datamllab/rlcard" target="_blank" rel="noreferrer">https://github.com/datamllab/rlcard</a></p><p>Pages: <a href="http://www.rlcard.org/" target="_blank" rel="noreferrer">http://www.rlcard.org/</a></p><h2 id="openspiel" tabindex="-1">OpenSpiel <a class="header-anchor" href="#openspiel" aria-label="Permalink to “OpenSpiel”">​</a></h2><p>OpenSpiel，是一个强化学习环境和算法的集合。用于研究强化学习算法和游戏中的搜索/规划。OpenSpiel 的目的是通过与一般游戏类似的方式促进跨多种不同游戏类型的一般多智能体强化学习，但是重点是强调学习而不是竞争形式。当前版本的 OpenSpiel 包含 20 多种游戏的不同类型（完全信息、同步移动、不完全信息、网格世界游戏、博弈游戏和某些普通形式/矩阵游戏）实现。</p><p>核心的 OpenSpiel 实现基于 C ++ 和 Python 绑定，这有助于在不同的深度学习框架中采用。该框架包含一系列游戏，允许 DRL agent 学会合作和竞争行为。同时， OpenSpiel 还包括搜索、优化和单一 agent 等多种 DRL 算法组合。OpenSpiel 还包括用于分析学习动态和其他常见评估指标的工具。</p><h3 id="支持的游戏" tabindex="-1">支持的游戏 <a class="header-anchor" href="#支持的游戏" aria-label="Permalink to “支持的游戏”">​</a></h3><p>Spiel 意指桌面游戏。因此， OpenSpiel 中的环境就是相关棋牌类游戏。一共有 28 款：</p><blockquote><p>双陆棋、突围棋、定约桥牌、Coin Game、屏风式四子棋、协作推箱子、国际象棋、第一价格密封拍卖、围棋、Goofspiel （一种多玩家纸牌游戏）</p><p>三宝棋、六贯棋、Kuhn 扑克、Leduc 扑克、大话骰、Markov Soccer、配对硬币（3 人游戏）、矩阵游戏、Oshi-Zumo、西非播棋、转盘五子棋、Phantom 三连棋</p><p>Pig 游戏、三连棋、Tiny Bridge、Y （一种棋类游戏）、Catch （仅支持 Python）、Cliff-Walking 在悬崖边走的醉汉（仅支持 Python）。</p></blockquote><h3 id="支持的算法" tabindex="-1">支持的算法 <a class="header-anchor" href="#支持的算法" aria-label="Permalink to “支持的算法”">​</a></h3><p>目前，在 OpenSpiel 中实现的算法一共有 24 种，分别是：</p><blockquote><p>极小化极大（Alpha-beta 剪枝）搜索、蒙特卡洛树搜索、序列形式线性规划、虚拟遗憾最小化（CFR）、Exploitability</p><p>外部抽样蒙特卡洛 CFR、结果抽样蒙特卡洛 CFR、Q-learning、价值迭代、优势动作评论算法(Advantage Actor Critic， A2C)、Deep Q-networks (DQN)</p><p>短期价值调整（EVA）、Deep CFR、Exploitability 下降(ED) 、（扩展形式）虚拟博弈（XFP）、神经虚拟自博弈(NFSP)、Neural Replicator Dynamics （NeuRD）</p><p>遗憾策略梯度（RPG, RMPG）、策略空间回应 oracle （PSRO）、基于 Q 的所有行动策略梯度（QPG）、回归 CFR (RCFR)、PSROrN、α-Rank、复制/演化动力学。</p></blockquote><h3 id="支持的博弈类型" tabindex="-1">支持的博弈类型 <a class="header-anchor" href="#支持的博弈类型" aria-label="Permalink to “支持的博弈类型”">​</a></h3><p>在 OpenSpiel 的游戏可以表示为各种广泛形式的博弈：</p><ul><li>常和博弈</li><li>零和博弈</li><li>协调博弈</li><li>一般博弈</li></ul><p>其中，常和博弈中智能体之间是严格的竞争关系，协调博弈中智能体之间是严格的竞争关系，一般博弈则介于两者之间。</p><p>另外，根据智能体能否获得博弈过程中的所有信息，又可以将博弈分为：</p><ul><li>完美信息博弈</li><li>不完美信息博弈</li></ul><p>象棋和围棋是没有偶然事件的完美信息博弈，双陆棋是有偶然事件的完美信息博弈，而像石头剪刀布、扑克这样的游戏属于不完美信息博弈。</p><ul><li>GitHub： <a href="https://github.com/deepmind/open_spiel" target="_blank" rel="noreferrer">https://github.com/deepmind/open_spiel</a></li></ul><h2 id="deep-rts" tabindex="-1">Deep RTS <a class="header-anchor" href="#deep-rts" aria-label="Permalink to “Deep RTS”">​</a></h2><p>DeepRTS 是一款用于强化学习研究的高性能实时策略游戏。它是为了提高性能而用 C++ 编写的，提供了一个 python 接口，以便更好地与机器学习工具包交互。深度 RTS 可以每秒超过<strong>6,000,000</strong>步处理游戏，渲染图形时可以达到<strong>2,000,000</strong>步。与《星际争霸》等其他解决方案相比，在配备 Nvidia RTX 2080 TI 的英特尔 i7-8700k 上运行的<strong>模拟时间快了 15 000% 以上。</strong></p><p>Deep RTS 的目标是通过减少计算时间，为 RTS AI 研究带来更实惠、更可持续的解决方案。</p><ul><li>Github: <a href="https://github.com/cair/deep-rts" target="_blank" rel="noreferrer">https://github.com/cair/deep-rts</a></li></ul><h2 id="microrts" tabindex="-1">MicroRTS <a class="header-anchor" href="#microrts" aria-label="Permalink to “MicroRTS”">​</a></h2><p><a href="https://github.com/Farama-Foundation/gym-microrts" target="_blank" rel="noreferrer">Gym-μRTS</a>在客观上与 Deep RTS 类似。现有的完整游戏具有很高的计算成本，通常意味着数千小时的 CPU 和 GPU 时间。这对研究来说是一个巨大的限制。</p><ul><li>Github: <a href="https://github.com/Farama-Foundation/MicroRTS-Py" target="_blank" rel="noreferrer">https://github.com/Farama-Foundation/MicroRTS-Py</a></li></ul><h2 id="nocturne" tabindex="-1">Nocturne <a class="header-anchor" href="#nocturne" aria-label="Permalink to “Nocturne”">​</a></h2><p><a href="https://github.com/facebookresearch/nocturne" target="_blank" rel="noreferrer">Nocturne</a>是 Facebook Research 发布的用于模拟多智能体系统的 RL 环境。 Nocturne 是具有部分可观察性的 2D 驾驶模拟环境。它是用 C++ 构建的，以提高速度。目前， Nocturne 可以处理来自<a href="https://github.com/waymo-research/waymo-open-dataset" target="_blank" rel="noreferrer">Waymo 开放数据集的</a>数据，但可以对其进行修改以处理其他数据源。使用 Python 库<code>nocturne</code>，人们能够训练自动驾驶汽车控制器来解决 Waymo 数据集（我们提供的基准）中的各种任务，然后使用我们提供的工具来评估设计的控制器。</p><p>利用这种丰富的数据源， Nocturne 包含了广泛的场景，其解决方案需要形成复杂的协调、心理理论和处理部分可观察性。</p><ul><li>GIthub: <a href="https://github.com/facebookresearch/nocturne" target="_blank" rel="noreferrer">https://github.com/facebookresearch/nocturne</a></li></ul><h2 id="cityflow-交通" tabindex="-1">CityFlow (交通) <a class="header-anchor" href="#cityflow-交通" aria-label="Permalink to “CityFlow (交通)”">​</a></h2><p><a href="https://github.com/cityflow-project/CityFlow/" target="_blank" rel="noreferrer">CityFlow</a>是一个针对大规模城市交通场景的多智能体强化学习环境。</p><p>它具有以下特点</p><ul><li><p>微观交通模拟器，模拟每辆车的行为，提供交通演变的最高级别细节。</p></li><li><p>支持路网和交通流的灵活定义</p></li><li><p>为强化学习提供友好的 Python 接口</p></li><li><p>快速地！精心设计的数据结构和多线程模拟算法。能够模拟全市交通。查看与 SUMO 的性能比较</p></li><li><p>Github: <a href="https://github.com/cityflow-project/CityFlow/" target="_blank" rel="noreferrer">https://github.com/cityflow-project/CityFlow/</a></p></li><li><p>Pages: <a href="https://cityflow.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">https://cityflow.readthedocs.io/en/latest/</a></p></li></ul><h2 id="airsim-自动驾驶汽车" tabindex="-1"><strong>AirSim （自动驾驶汽车）</strong> <a class="header-anchor" href="#airsim-自动驾驶汽车" aria-label="Permalink to “AirSim （自动驾驶汽车）”">​</a></h2><p>AirSim 结合了强化学习、深度学习和计算机视觉的力量，用于构建用于自动驾驶车辆的算法。它模拟无人机、汽车等自动驾驶车辆。AirSim 是一个由虚幻引擎环境开发的开源平台，可与 Unity 插件一起使用，其 API 可通过 C++、C#、Python 和 Java 访问。另一个有趣的事情是它与 PX4 等硬件飞行控制器兼容，可提供逼真的物理和虚拟体验。</p><p>Github: <a href="https://github.com/microsoft/AirSim" target="_blank" rel="noreferrer">https://github.com/microsoft/AirSim</a></p><h2 id="cyberbattlesim" tabindex="-1">CyberBattleSim <a class="header-anchor" href="#cyberbattlesim" aria-label="Permalink to “CyberBattleSim”">​</a></h2><p><a href="https://github.com/microsoft/CyberBattleSim" target="_blank" rel="noreferrer">CyberBattleSim</a>是一个框架，用于构建复杂计算机网络和系统的抽象模拟，以便应用强化学习。了解智能体如何在这种复杂的环境中交互和发展是很有帮助的。它本质上是网络安全的游戏化，以便可以应用强化学习。</p><p>CyberBattleSim 是一个实验研究平台，用于研究在模拟抽象企业网络环境中运行的自动化智能体的交互。该模拟提供了计算机网络和网络安全概念的高级抽象。其基于 Python 的 Open AI Gym 界面允许使用强化学习算法来训练自动化智能体。</p><p>模拟环境由固定的网络拓扑和一组漏洞参数化，智能体可以利用这些漏洞在网络中横向移动。攻击者的目标是通过利用计算机节点中植入的漏洞来获得部分网络的所有权。当攻击者试图在整个网络中传播时，防御者智能体会监视网络活动并尝试检测正在发生的任何攻击，并通过驱逐攻击者来减轻对系统的影响。我们提供了一个基本的随机防御者，可以根据预定义的成功概率来检测和减轻正在进行的攻击。我们通过重新镜像受感染的节点来实施缓解措施，该过程被抽象建模为跨越多个模拟步骤的操作。</p><p>为了比较智能体的性能，我们查看两个指标：为实现目标而采取的模拟步骤数量以及整个训练时期模拟步骤的累积奖励。</p><ul><li>Github： <a href="https://github.com/microsoft/CyberBattleSim" target="_blank" rel="noreferrer">https://github.com/microsoft/CyberBattleSim</a></li></ul><h2 id="textworld" tabindex="-1">Textworld <a class="header-anchor" href="#textworld" aria-label="Permalink to “Textworld”">​</a></h2><p>TextWorld 是微软构建的开源引擎，有利于生成和模拟文本游戏。借助强化学习，我们可以训练智能体学习语言理解和基础知识以及决策能力。</p><ul><li>Github: <a href="https://github.com/microsoft/TextWorld" target="_blank" rel="noreferrer">https://github.com/microsoft/TextWorld</a></li></ul><h2 id="tensortrade-通过强化学习进行高效交易" tabindex="-1">TensorTrade：通过强化学习进行高效交易 <a class="header-anchor" href="#tensortrade-通过强化学习进行高效交易" aria-label="Permalink to “TensorTrade：通过强化学习进行高效交易”">​</a></h2><p>TensorTrade 是一个开源 Python 框架，用于使用强化学习构建、训练、评估和部署强大的交易算法。该框架注重高度可组合性和可扩展性，使系统能够从单个 CPU 上的简单交易策略扩展到在 HPC 机器分布上运行的复杂投资策略。</p><p>在底层，该框架使用现有机器学习库中的许多 API 来维护高质量的数据管道和学习模型。</p><h2 id="habitat-lab" tabindex="-1">Habitat-Lab <a class="header-anchor" href="#habitat-lab" aria-label="Permalink to “Habitat-Lab”">​</a></h2><p>Habitat-Lab 是一个模块化高级库，用于具体人工智能的端到端开发。它旨在训练智能体在室内环境中执行各种具体的人工智能任务，并开发可以在执行这些任务时与人类交互的智能体。</p><p>为了实现这一目标， Habitat-Lab 旨在支持以下功能：</p><ul><li><strong>灵活的任务定义</strong>：允许用户在各种单智能体和多智能体任务中训练智能体（例如导航、重新排列、遵循指令、回答问题、人类跟随），以及定义新颖的任务。</li><li><strong>多样化的体现智能体</strong>：配置和实例化一组多样化的体现智能体，包括商业机器人和人形机器人，指定它们的传感器和功能。</li><li><strong>训练和评估智能体</strong>：提供用于单智能体和多智能体训练的算法（通过模仿或强化学习，或者像 SensePlanAct 管道中那样根本不学习），以及使用标准指标在定义的任务上对其性能进行基准测试的工具。</li><li><strong>人机交互</strong>：为人类与模拟器交互提供框架，从而能够收集具体数据或与训练有素的智能体交互。</li></ul><p>Habitat-Lab 用作<a href="https://github.com/facebookresearch/habitat-sim" target="_blank" rel="noreferrer"><code>Habitat-Sim</code></a>核心模拟器。</p><ul><li>Github: <a href="https://github.com/facebookresearch/habitat-lab" target="_blank" rel="noreferrer">https://github.com/facebookresearch/habitat-lab</a></li><li>文档资源： <a href="https://aihabitat.org/" target="_blank" rel="noreferrer">https://aihabitat.org/</a></li></ul><h2 id="bsuite-强化学习行为套件" tabindex="-1"><code>bsuite</code> 强化学习行为套件 <a class="header-anchor" href="#bsuite-强化学习行为套件" aria-label="Permalink to “bsuite 强化学习行为套件”">​</a></h2><p><em>bsuite</em>是精心设计的实验的集合，旨在研究强化学习 (RL) 智能体的核心功能，有两个主要目标。</p><ul><li>收集清晰、信息丰富且可扩展的问题，捕获高效和通用学习算法设计中的关键问题。</li><li>通过智能体在这些共享基准上的表现来研究智能体的行为。</li></ul><p>该库可自动根据这些基准对任何智能体进行评估和分析。它有助于促进对 RL 核心问题的可重复且可访问的研究，并最终设计出卓越的学习算法。</p><ul><li>Github: <a href="https://github.com/google-deepmind/bsuite" target="_blank" rel="noreferrer">https://github.com/google-deepmind/bsuite</a></li></ul><h2 id="google-research-football" tabindex="-1">Google Research Football <a class="header-anchor" href="#google-research-football" aria-label="Permalink to “Google Research Football”">​</a></h2><p><em>Google Research Football</em>是一个新颖的 RL 环境，智能体的目标是掌握世界上最受欢迎的运动——足球！足球环境以流行的足球视频游戏为蓝本，提供了一种高效的基于物理的 3D 足球模拟，其中智能体控制球队中的一名或所有足球运动员，学习如何在他们之间传球，并设法克服对手的防守以得分目标。足球环境提供了一组要求很高的研究问题，称为足球基准，以及足球学院，一组逐渐困难的强化学习场景。 它非常适合多主体和多任务研究。它还允许您根据所包含的示例使用模拟器创建自己的学院场景以及全新的任务。</p><ul><li>Github: <a href="https://github.com/google-research/football" target="_blank" rel="noreferrer">https://github.com/google-research/football</a></li></ul><h2 id="metaworld" tabindex="-1">Metaworld <a class="header-anchor" href="#metaworld" aria-label="Permalink to “Metaworld”">​</a></h2><p>元强化学习算法可以通过利用先前的经验来学习如何学习，从而使机器人能够更快地获得新技能。<em>Meta-World</em>是元强化学习和多任务学习的开源模拟基准，由 50 个不同的机器人操作任务组成。作者的目标是提供足够广泛的任务分布来评估元强化学习算法对新行为的泛化能力。</p><ul><li>Github: <a href="https://github.com/Farama-Foundation/Metaworld" target="_blank" rel="noreferrer">https://github.com/Farama-Foundation/Metaworld</a></li></ul><h2 id="minerl" tabindex="-1">MineRL <a class="header-anchor" href="#minerl" aria-label="Permalink to “MineRL”">​</a></h2><p><em>MineRL</em>是卡内基梅隆大学发起的一个研究项目，旨在开发 Minecraft 中人工智能的各个方面。简而言之， MineRL 由两个主要组件组成：</p><ul><li><p><a href="https://minerl.io/dataset/" target="_blank" rel="noreferrer">MineRL-v0 数据集</a>– 最大的模仿学习数据集之一，拥有超过 6000 万帧记录的人类玩家数据。该数据集包含一组环境，突出了现代强化学习中许多最困难的问题：稀疏奖励和分层策略。</p></li><li><p><a href="https://minerl.io/docs/tutorials/index.html" target="_blank" rel="noreferrer">minerl</a> – 一个丰富的 python3 包，用于在 Minecraft 中进行人工智能研究。这包括两个主要子模块：<em>minerl.env</em> - Minecraft 中不断增长的 OpenAI Gym 环境集和<em>minerl.data</em> - 用于试验 MineRL-v0 数据集的主要 Python 模块。</p></li><li><p>Github: <a href="https://github.com/minerllabs" target="_blank" rel="noreferrer">https://github.com/minerllabs</a></p></li><li><p>文档列表： <a href="https://minerl.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">https://minerl.readthedocs.io/en/latest/</a></p></li></ul><h2 id="procgen-benchmark" tabindex="-1">Procgen Benchmark <a class="header-anchor" href="#procgen-benchmark" aria-label="Permalink to “Procgen Benchmark”">​</a></h2><p><em>Procgen Benchmark</em>由 16 个独特的环境组成，旨在衡量强化学习中的样本效率和泛化能力。该基准非常适合评估泛化性，因为可以在每个环境中生成不同的训练和测试集。该基准测试也非常适合评估样本效率，因为所有环境都给 RL 智能体带来了多样化且引人注目的挑战。环境的内在多样性要求智能体学习稳健的策略；过度拟合状态空间中的狭窄区域是不够的。换句话说，当智能体面临不断变化的水平时，概括能力就成为成功不可或缺的组成部分。</p><ul><li>Github： <a href="https://github.com/openai/procgen" target="_blank" rel="noreferrer">https://github.com/openai/procgen</a></li><li>文档： <a href="https://openai.com/blog/procgen-benchmark/" target="_blank" rel="noreferrer">https://openai.com/blog/procgen-benchmark/</a></li></ul><h2 id="星际争霸-2" tabindex="-1">星际争霸 2 <a class="header-anchor" href="#星际争霸-2" aria-label="Permalink to “星际争霸 2”">​</a></h2><p><em>PySC2</em>为 RL 智能体提供了一个与《星际争霸 2》交互的接口，获取观察结果并发送操作。它将暴雪娱乐的星际争霸 II 机器学习 API 作为 Python RL 环境公开。这是 DeepMind 和暴雪之间的合作，旨在将《星际争霸 II》开发成一个丰富的 RL 研究环境。<em>PySC2</em>有许多预先配置的迷你游戏地图，用于对 RL 智能体进行基准测试。</p><ul><li>Github: <a href="https://github.com/google-deepmind/pysc2" target="_blank" rel="noreferrer">https://github.com/google-deepmind/pysc2</a></li></ul><h2 id="unity-机器学习智能体工具包-ml-agents" tabindex="-1">Unity 机器学习智能体工具包 (ML-Agents） <a class="header-anchor" href="#unity-机器学习智能体工具包-ml-agents" aria-label="Permalink to “Unity 机器学习智能体工具包 (ML-Agents）”">​</a></h2><p><strong>Unity 机器学习智能体工具包</strong>(ML-Agents) 是一个开源项目，使游戏和模拟能够作为训练智能体的环境。我们提供最先进算法的实现（基于 PyTorch），使游戏开发者和爱好者能够轻松训练 2D、3D 和 VR/AR 游戏的智能体。研究人员还可以使用提供的简单易用的 Python API 来使用强化学习、模仿学习、神经进化或任何其他方法来训练智能体。这些训练有素的智能体可用于多种目的，包括控制 NPC 行为（在多种设置中，例如多智能体和对抗）、游戏构建的自动测试以及评估预发布的不同游戏设计决策。 ML-Agents 工具包对于游戏开发人员和 AI 研究人员来说是互惠互利的，因为它提供了一个中央平台，可以在 Unity 丰富的环境中评估 AI 的进步，然后让更广泛的研究和游戏开发人员社区可以访问。</p><ul><li>Github: <a href="https://github.com/Unity-Technologies/ml-agents" target="_blank" rel="noreferrer">https://github.com/Unity-Technologies/ml-agents</a></li><li>文档： <a href="https://unity.com/products/machine-learning-agents" target="_blank" rel="noreferrer">https://unity.com/products/machine-learning-agents</a></li></ul><h1 id="仿真引擎加速" tabindex="-1">仿真引擎加速 <a class="header-anchor" href="#仿真引擎加速" aria-label="Permalink to “仿真引擎加速”">​</a></h1><h2 id="isaacgymenvs" tabindex="-1">IsaacGymEnvs <a class="header-anchor" href="#isaacgymenvs" aria-label="Permalink to “IsaacGymEnvs”">​</a></h2><p>特点：基于 Cuda 重写了强化学习的环境模拟，使得环境模拟可以使用 gpu 进行加速</p><ul><li>项目地址： <a href="https://github.com/NVIDIA-Omniverse/IsaacGymEnvs/" target="_blank" rel="noreferrer">https://github.com/NVIDIA-Omniverse/IsaacGymEnvs/</a></li><li>在线文档： <a href="https://developer.nvidia.com/isaac-gym" target="_blank" rel="noreferrer">https://developer.nvidia.com/isaac-gym</a></li><li>arXiv 链接： <a href="https://arxiv.org/abs/2108.10470" target="_blank" rel="noreferrer">https://arxiv.org/abs/2108.10470</a></li></ul><h2 id="envpool" tabindex="-1">Envpool <a class="header-anchor" href="#envpool" aria-label="Permalink to “Envpool”">​</a></h2><p><strong>EnvPool 是一个基于 C++ 、高效、通用的强化学习并行环境（vectorized environment）模拟器</strong></p><ul><li>项目地址： <a href="https://github.com/sail-sg/envpool" target="_blank" rel="noreferrer">https://github.com/sail-sg/envpool</a></li><li>在线文档： <a href="https://envpool.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">https://envpool.readthedocs.io/en/latest/</a></li><li>arXiv 链接： <a href="https://arxiv.org/abs/2206.10558" target="_blank" rel="noreferrer">https://arxiv.org/abs/2206.10558</a></li></ul><h2 id="madrona" tabindex="-1">Madrona <a class="header-anchor" href="#madrona" aria-label="Permalink to “Madrona”">​</a></h2><p>Madrona 是一款研究型游戏引擎，专为创建学习环境而设计，可以在单个 GPU 上同时运行数千个环境实例，并且以极高的吞吐量（每秒数百万个聚合步骤）执行。Madrona 的目标是让研究人员更轻松地为各种任务创建新的高性能环境，从而使 AI 智能体训练的速度提高几个数量级。</p><p>Madrona 具有以下特点：</p><ul><li>GPU 批量模拟：单个 GPU 上可运行数千个环境；</li><li>实体组件系统 (ECS) 架构；</li><li>可与 PyTorch 轻松互操作。</li></ul><p>Github: <a href="https://github.com/shacklettbp/madrona" target="_blank" rel="noreferrer">https://github.com/shacklettbp/madrona</a></p><p>文档： <a href="https://madrona-engine.github.io/" target="_blank" rel="noreferrer">https://madrona-engine.github.io/</a></p><h1 id="其他资源链接" tabindex="-1">其他资源链接 <a class="header-anchor" href="#其他资源链接" aria-label="Permalink to “其他资源链接”">​</a></h1><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>分类</th><th>Introduction</th><th>Github</th><th>Star</th></tr></thead><tbody><tr><td>网络攻防</td><td>将强化学习应用于网络安全的精选资源列表</td><td><a href="https://github.com/Limmen/awesome-rl-for-cybersecurity" target="_blank" rel="noreferrer">Limmen/awesome-rl-for-cybersecurity</a></td><td>600+</td></tr><tr><td>通用</td><td>强化学习环境的综合列表</td><td><a href="https://github.com/clvrai/awesome-rl-envs" target="_blank" rel="noreferrer">clvrai/awesome-rl-envs</a></td><td>900+</td></tr><tr><td></td><td></td><td></td><td></td></tr></tbody></table></div>',145)])])}const c=a(i,[["render",o]]);export{d as __pageData,c as default};
